sparql:
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?work WHERE { ?work rdfs:label ?label . FILTER(CONTAINS(LCASE(?label), "mozart")) . ?work a efrbroo:F22_Self_Associated_Work . }

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?component
WHERE {
  <http://data.doremus.org/expression/0578c731-d003-373b-8c17-a837dd5c109d> efrbroo:R5_has_component ?component
}

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
PREFIX ecrm: <http://erlangen-crm.org/current/>
SELECT ?artist ?birthDate WHERE { ?artist a ecrm:E21_Person . ?artist ecrm:P102_has_title ?name . ?artist ecrm:P14_carried_out ?performance . ?performance efrbroo:R25_performed ?expression . ?expression ecrm:P102_has_title ?expressionTitle . FILTER CONTAINS(?expressionTitle, "oboe") . ?artist ecrm:P131_is_identified_by ?birthDate }

PREFIX doremus: <http://data.doremus.org/ontology#>
SELECT DISTINCT ?manifestation WHERE {
  <http://data.doremus.org/track/fc7ef52d-4e18-3a10-99af-ed6391342ceb> doremus:U51_is_partial_or_full_recording_of ?manifestation
}

SELECT ?entity ?duration WHERE { 
  ?entity <http://data.doremus.org/ontology#U78_estimated_duration> ?duration . 
}

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?work WHERE { <http://data.doremus.org/artist/b82c0771-5280-39af-ad2e-8ace2f4ebda3> efrbroo:R17i_was_created_by ?work . ?work dct:created ?date . FILTER (year(?date) = 1853) }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ecrm: <http://erlangen-crm.org/current/>
SELECT ?birthYear WHERE { <http://data.doremus.org/artist/60f784a6-2927-38e4-9379-e4bf4fc695b2> ecrm:P98i_was_born ?birthEvent . ?birthEvent ecrm:P4_has_time-span ?timeSpan . ?timeSpan rdfs:label ?birthYear }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?artist WHERE { ?artist a efrbroo:F18_Artist ; rdfs:label ?label . FILTER (regex(?label, "Trumpet Boy", "i")) }

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
PREFIX dct: <http://purl.org/dc/terms/>
SELECT ?work WHERE { <http://data.doremus.org/artist/c536e11e-7871-3469-b913-1883b0b60e98> dct:creator ?work . ?work a efrbroo:F23_Expression . }

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?performance WHERE { ?performance a efrbroo:F31_Performance ;
    <http://data.doremus.org/ontology#U65_has_geographical_context> <http://data.doremus.org/context/c54563e5-dc9b-36a0-83df-52616f810ad7> . }

PREFIX ecrm: <http://erlangen-crm.org/current/>
SELECT ?recording ?title WHERE {
  ?recording ecrm:P102_has_title ?title ;
             <http://data.doremus.org/ontology#U51_is_partial_or_full_recording_of> <http://data.doremus.org/expression/ee0ab77c-5736-3c3f-9a54-bf7385faa763> .
}
